    // Build a file large enough to span multiple read chunks (default highWaterMark is 64KB)
    // Include multi-byte UTF-8 sequences so that without proper utf-8 encoding on the stream,
    // characters may be split across chunk boundaries causing JSON parse errors
    const rows: string[] = [];
