      // Include 4-byte UTF-8 characters (emoji) which are most likely to be split at boundaries
      rows.push(JSON.stringify({ key: `k${i}`, val: `${padding}\u{1F600}\u{1F4A9}\u{1F680}${i}` }) + '\n');
