```typescript
import * as fs from 'fs';
import * as path from 'path';
import * as os from 'os';
import { Dirty } from '../../../../../../../../../../../subject_repositories/node-dirty/lib/dirty/dirty.js';

describe('Dirty', () => {
  it('should correctly load data when a multi-byte UTF-8 character straddles a read chunk boundary', (done) => {
    const tmpDir = os.tmpdir();
    const dbPath = path.join(tmpDir, `dirty-boundary-${process.pid}.db`);

    // Default highWaterMark for fs.createReadStream = 65536 bytes
    // Place é (UTF-8: 0xC3 0xA9) so byte 0xC3 is the last byte of chunk 1
    // and byte 0xA9 is the first byte of chunk 2
    const HWM = 65536;
    const prefix = '{"key":"k","val":"'; // 18 ASCII bytes
    const eAccent = '\u00e9';             // é: [0xC3, 0xA9]
    const suffix = '"}\n';               // 3 ASCII bytes

    // padding fills bytes 18..(HWM-2), length = HWM - 1 - 18 = 65517
    const paddingLen = HWM - 1 - prefix.length;
    const padding = 'a'.repeat(paddingLen);

    const contentBytes = Buffer.from(prefix + padding + eAccent + suffix, 'utf-8');

    // Sanity check byte layout
    if (contentBytes[HWM - 1] !== 0xC3 || contentBytes[HWM] !== 0xA9) {
      done(new Error(`Unexpected byte layout: [${HWM-1}]=0x${contentBytes[HWM-1].toString(16)}, [${HWM}]=0x${contentBytes[HWM].toString(16)}`));
      return;
    }

    fs.writeFileSync(dbPath, contentBytes);

    const errors: Error[] = [];
    const db = new Dirty(dbPath);

    db.on('error', (err: Error) => errors.push(err));
    db.on('load', (count: number) => {
      try {
        expect(errors).toHaveLength(0);
        expect(count).toBe(1);
        expect(db.get('k')).toBe(padding + eAccent);
        done();
      } catch (e) {
        done(e);
      } finally {
        try { fs.unlinkSync(dbPath); } catch (e) {}
      }
    });
  });
});
